+/**
+ * Remove potentially dangerous elements and attributes from an SVG document
+ * to prevent XSS attacks.
+ * @param {Document} svgDocument - The parsed SVG document to sanitize
+ */
+const sanitizeSvg = function (svgDocument) {
+    // Remove script elements
+    const scripts = svgDocument.querySelectorAll('script');
+    scripts.forEach(script => script.parentNode.removeChild(script));
+
+    // Remove elements with dangerous attributes (event handlers, javascript: URLs)
+    const allElements = svgDocument.querySelectorAll('*');
+    allElements.forEach(element => {
+        const attributesToRemove = [];
+        for (let i = 0; i < element.attributes.length; i++) {
+            const attr = element.attributes[i];
+            // Remove event handler attributes (on*)
+            if (attr.name.toLowerCase().startsWith('on')) {
+                attributesToRemove.push(attr.name);
+            }
+            // Remove attributes with javascript: URLs
+            if (attr.value.toLowerCase().replace(/\s/g, '').includes('javascript:')) {
+                attributesToRemove.push(attr.name);
+            }
+        }
+        attributesToRemove.forEach(attrName => element.removeAttribute(attrName));
+    });
+
+    // Remove use elements that reference external resources
+    const useElements = svgDocument.querySelectorAll('use');
+    useElements.forEach(useEl => {
+        const href = useEl.getAttribute('href') || useEl.getAttribute('xlink:href');
+        if (href && (href.startsWith('http') || href.startsWith('//'))) {
+            useEl.parentNode.removeChild(useEl);
+        }
+    });
+
+    // Remove foreignObject elements which can contain arbitrary HTML
+    const foreignObjects = svgDocument.querySelectorAll('foreignObject');
+    foreignObjects.forEach(fo => fo.parentNode.removeChild(fo));
+};
