+
+#[derive(Debug, Deserialize, Serialize)]
+#[serde(rename_all = "camelCase")]
+pub struct QeIdentityBody {
+    pub id: String,
+    pub version: u32,
+    pub issue_date: String,
+    pub next_update: String,
+    pub tcb_evaluation_data_number: u32,
+    pub miscselect: String,
+    pub miscselect_mask: String,
+    pub attributes: String,
+    pub attributes_mask: String,
+    pub mrsigner: String,
+    pub isvprodid: u32,
+    pub tcb_levels: Vec<QeTcbLevel>,
+}
+
+#[derive(Debug, Deserialize, Serialize)]
+#[serde(rename_all = "camelCase")]
+pub struct QeTcbLevel {
+    pub tcb: QeTcb,
+    pub tcb_date: String,
+    pub tcb_status: String,
+    #[serde(default)]
+    pub advisory_ids: Vec<String>,
+}
+
+#[derive(Debug, Deserialize, Serialize)]
+pub struct QeTcb {
+    pub isvsvn: u32,
+}
+
+#[derive(Debug, Deserialize, Serialize)]
+#[serde(rename_all = "camelCase")]
+pub struct QeIdentityWrapper {
+    pub enclave_identity: QeIdentityBody,
+    pub signature: String,
+}
+
+/// Verify the QE Identity signature against the issuer certificate chain.
+///
+/// The signature is over the raw JSON bytes of the `enclaveIdentity` field.
+/// The signing key is the leaf certificate in the issuer chain, which must
+/// chain up to a trusted Intel root.
+pub fn verify_qe_identity_signature(
+    qe_identity_json: &str,
+    qe_identity_signature: &str,
+    qe_identity_issuer_chain: &str,
+    now: u64,
+) -> Result<()> {
+    // Parse the wrapper to extract the raw enclaveIdentity bytes and signature
+    let wrapper: QeIdentityWrapper = serde_json::from_str(qe_identity_json)
+        .context("Failed to parse QE Identity JSON")?;
+
+    // The signature covers the raw bytes of the enclaveIdentity JSON value.
+    // We need to extract the exact bytes from the original JSON string.
+    let raw_identity_bytes = extract_raw_field(qe_identity_json, "enclaveIdentity")
+        .context("Failed to extract raw enclaveIdentity field")?;
+
+    // Decode the hex signature
+    let sig_bytes = hex::decode(qe_identity_signature)
+        .context("Failed to decode QE Identity signature hex")?;
+
+    // Parse the issuer certificate chain (PEM encoded, URL-percent-encoded)
+    let chain_pem = percent_encoding::percent_decode_str(qe_identity_issuer_chain)
+        .decode_utf8()
+        .context("Failed to URL-decode QE Identity issuer chain")?;
+
+    let certs = parse_pem_chain(&chain_pem)
+        .context("Failed to parse QE Identity issuer certificate chain")?;
+
+    if certs.is_empty() {
+        bail!("QE Identity issuer certificate chain is empty");
+    }
+
+    // Verify the certificate chain validity
+    verify_certificate_chain(&certs, now)
+        .context("QE Identity issuer certificate chain validation failed")?;
+
+    // The leaf certificate's public key is used to verify the signature
+    let leaf_cert = &certs[0];
+    let pub_key = extract_public_key(leaf_cert)
+        .context("Failed to extract public key from QE Identity issuer leaf certificate")?;
+
+    // Verify ECDSA-P256-SHA256 signature over the raw enclaveIdentity bytes
+    crypto::verify_p256_signature_der(raw_identity_bytes.as_bytes(), &sig_bytes, &pub_key)
+        .context("QE Identity signature verification failed")?;
+
+    Ok(())
+}
+
+/// Check the QE Report fields against the QE Identity policy.
+///
+/// Enforces:
+/// - MRSIGNER matches the value in QE Identity
+/// - ISVPRODID matches the value in QE Identity
+/// - ISVSVN is at or above the minimum required level from QE Identity TCB levels
+pub fn check_qe_report_against_identity(
+    qe_report: &crate::quote::QeReport,
+    qe_identity_json: &str,
+) -> Result<()> {
+    let wrapper: QeIdentityWrapper = serde_json::from_str(qe_identity_json)
+        .context("Failed to parse QE Identity JSON for policy check")?;
+    let identity = &wrapper.enclave_identity;
+
+    // Verify MRSIGNER
+    let expected_mrsigner = hex::decode(&identity.mrsigner)
+        .context("Failed to decode MRSIGNER hex from QE Identity")?;
+    if qe_report.mrsigner != expected_mrsigner.as_slice() {
+        bail!(
+            "QE Report MRSIGNER mismatch: expected {}, got {}",
+            identity.mrsigner,
+            hex::encode(&qe_report.mrsigner)
+        );
+    }
+
+    // Verify ISVPRODID
+    if qe_report.isvprodid != identity.isvprodid as u16 {
+        bail!(
+            "QE Report ISVPRODID mismatch: expected {}, got {}",
+            identity.isvprodid,
+            qe_report.isvprodid
+        );
+    }
+
+    // Verify ISVSVN against TCB levels — find the highest UpToDate level
+    // whose isvsvn <= qe_report.isvsvn
+    let report_isvsvn = qe_report.isvsvn as u32;
+    let tcb_status = identity
+        .tcb_levels
+        .iter()
+        .filter(|level| level.tcb.isvsvn <= report_isvsvn)
+        .max_by_key(|level| level.tcb.isvsvn)
+        .map(|level| level.tcb_status.as_str())
+        .unwrap_or("Revoked");
+
+    if tcb_status != "UpToDate" && tcb_status != "SWHardeningNeeded" {
+        bail!(
+            "QE TCB level is not acceptable: status={} for ISVSVN={}",
+            tcb_status,
+            report_isvsvn
+        );
+    }
+
+    Ok(())
+}
+
+/// Extract the raw JSON bytes of a named field from a JSON string.
+fn extract_raw_field<'a>(json: &'a str, field: &str) -> Result<&'a str> {
+    let key = format!("\"{}\"", field);
+    let key_pos = json
+        .find(&key)
+        .ok_or_else(|| anyhow!("Field '{}' not found in JSON", field))?;
+    let after_key = &json[key_pos + key.len()..];
+    let colon_pos = after_key
+        .find(':')
+        .ok_or_else(|| anyhow!("No colon after field '{}'", field))?;
+    let after_colon = after_key[colon_pos + 1..].trim_start();
+    // Find the matching closing brace/bracket
+    if !after_colon.starts_with('{') {
+        bail!("Field '{}' is not a JSON object", field);
+    }
+    let mut depth = 0usize;
+    let mut end = 0usize;
+    for (i, ch) in after_colon.char_indices() {
+        match ch {
+            '{' => depth += 1,
+            '}' => {
+                depth -= 1;
+                if depth == 0 {
+                    end = i + 1;
+                    break;
+                }
+            }
+            _ => {}
+        }
+    }
+    if end == 0 {
+        bail!("Could not find end of field '{}' JSON object", field);
+    }
+    Ok(&after_colon[..end])
+}

